-- calc_series_name
-- Field: Series.Name
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_series_name(p_serie_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT series_number FROM series WHERE serie_id = p_serie_id), '-', (SELECT NULLIF(show_code, '') FROM series WHERE serie_id = p_serie_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_series_total_seasons
-- Field: Series.TotalSeasons
-- Type: aggregation | DataType: integer | Returns: INTEGER

CREATE OR REPLACE FUNCTION calc_series_total_seasons(p_serie_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM seasons WHERE series = (SELECT NULLIF(serie_id, '') FROM series WHERE serie_id = p_serie_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_series_total_episodes
-- Field: Series.TotalEpisodes
-- Type: aggregation | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_series_total_episodes(p_serie_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_seasons_episode_count(season_id))::numeric), 0) FROM seasons WHERE series = p_serie_id))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_series_is_long_running
-- Field: Series.IsLongRunning
-- Type: calculated | DataType: boolean | Returns: BOOLEAN

CREATE OR REPLACE FUNCTION calc_series_is_long_running(p_serie_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_series_total_episodes(p_serie_id))::NUMERIC > 50)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_series_rating
-- Field: Series.Rating
-- Type: aggregation | DataType: number | Returns: NUMERIC

CREATE OR REPLACE FUNCTION calc_series_rating(p_serie_id TEXT)
RETURNS NUMERIC AS $$
