-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_ratings_name(p_rating_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(calc_ratings_display_name(p_rating_id), '-', (SELECT NULLIF(users_name, '') FROM ratings WHERE rating_id = p_rating_id)))::text;
$$ LANGUAGE sql STABLE;

-- calc_ratings_display_name
-- Field: Ratings.DisplayName
-- Type: calculated | DataType: string | Returns: TEXT

CREATE OR REPLACE FUNCTION calc_ratings_display_name(p_rating_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (SELECT NULLIF(series, '') FROM ratings WHERE rating_id = p_rating_id) IS NULL THEN (CONCAT('Episode: ', calc_ratings_episode_name(p_rating_id)))::text ELSE (CONCAT('Series: ', calc_ratings_series_name(p_rating_id)))::text END)::text;
$$ LANGUAGE sql STABLE;

-- ============================================================================
-- MANY-SIDE RELATIONSHIP FUNCTIONS
-- These functions aggregate child records for many-side relationships
-- ============================================================================

-- calc_series_seasons
-- Field: Series.Seasons
-- Type: Many-side relationship (backref) to Seasons
-- Aggregates: Seasons.SeasonId where Series = parent
CREATE OR REPLACE FUNCTION calc_series_seasons(p_serie_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(season_id::TEXT, ', ' ORDER BY season_id)
    FROM seasons
    WHERE series = p_serie_id
  );
$$ LANGUAGE sql STABLE;

-- calc_series_series_ratings
-- Field: Series.SeriesRatings
-- Type: Many-side relationship (backref) to Ratings
-- Aggregates: Ratings.RatingId where Series = parent
CREATE OR REPLACE FUNCTION calc_series_series_ratings(p_serie_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(rating_id::TEXT, ', ' ORDER BY rating_id)
    FROM ratings
    WHERE series = p_serie_id
  );
$$ LANGUAGE sql STABLE;

-- calc_seasons_episodes
-- Field: Seasons.Episodes
-- Type: Many-side relationship (backref) to Episodes
-- Aggregates: Episodes.EpisodeId where Season = parent
CREATE OR REPLACE FUNCTION calc_seasons_episodes(p_season_id TEXT)
RETURNS TEXT AS $$
  SELECT (
    SELECT STRING_AGG(episode_id::TEXT, ', ' ORDER BY episode_id)
    FROM episodes
    WHERE season = p_season_id
  );
$$ LANGUAGE sql STABLE;

